<script setup>
import { ref, computed, onMounted, onUnmounted } from 'vue'
import { useRoute, useRouter } from 'vue-router'
import GraphPanel from '../components/GraphPanel.vue'
import Step2EnvSetup from '../components/Step2EnvSetup.vue'
import { getProject, getGraphData } from '../api/graph'
import { getSimulation, stopSimulation, getEnvStatus, closeSimulationEnv } from '../api/simulation'

const route = useRoute()
const router = useRouter()

// Props
const props = defineProps({
  simulationId: String
})

// Layout State
const viewMode = ref('split')

// Data State
const currentSimulationId = ref(route.params.simulationId)
const projectData = ref(null)
const graphData = ref(null)
const graphLoading = ref(false)
const systemLogs = ref([])
const currentStatus = ref('processing') // processing | completed | error

// --- Computed Layout Styles ---
const leftPanelStyle = computed(() => {
  if (viewMode.value === 'graph') return { width: '100%', opacity: 1, transform: 'translateX(0)' }
  if (viewMode.value === 'workbench') return { width: '0%', opacity: 0, transform: 'translateX(-20px)' }
  return { width: '50%', opacity: 1, transform: 'translateX(0)' }
})

const rightPanelStyle = computed(() => {
  if (viewMode.value === 'workbench') return { width: '100%', opacity: 1, transform: 'translateX(0)' }
  if (viewMode.value === 'graph') return { width: '0%', opacity: 0, transform: 'translateX(20px)' }
  return { width: '50%', opacity: 1, transform: 'translateX(0)' }
})

// --- Status Computed ---
const statusClass = computed(() => {
  return currentStatus.value
})

const statusText = computed(() => {
  if (currentStatus.value === 'error') return 'Error'
  if (currentStatus.value === 'completed') return 'Ready'
  return 'Preparing'
})

// --- Helpers ---
const addLog = (msg) => {
  const time = new Date().toLocaleTimeString('en-US', { hour12: false, hour: '2-digit', minute: '2-digit', second: '2-digit' }) + '.' + new Date().getMilliseconds().toString().padStart(3, '0')
  systemLogs.value.push({ time, msg })
  if (systemLogs.value.length > 100) {
    systemLogs.value.shift()
  }
}

const updateStatus = (status) => {
  currentStatus.value = status
}

// --- Layout Methods ---
const toggleMaximize = (target) => {
  if (viewMode.value === target) {
    viewMode.value = 'split'
  } else {
    viewMode.value = target
  }
}

const handleGoBack = () => {
  // 杩斿洖鍒?process 椤甸潰
  if (projectData.value?.project_id) {
    router.push({ name: 'Process', params: { projectId: projectData.value.project_id } })
  } else {
    router.push('/')
  }
}

const handleNextStep = (params = {}) => {
  addLog('杩涘叆 Step 3: 寮€濮嬫ā鎷?)
  
  // 璁板綍妯℃嫙杞暟閰嶇疆
  if (params.maxRounds) {
    addLog(`鑷畾涔夋ā鎷熻疆鏁? ${params.maxRounds} 杞甡)
  } else {
    addLog('浣跨敤鑷姩閰嶇疆鐨勬ā鎷熻疆鏁?)
  }
  
  // 鏋勫缓璺敱鍙傛暟
  const routeParams = {
    name: 'SimulationRun',
    params: { simulationId: currentSimulationId.value }
  }
  
  // 濡傛灉鏈夎嚜瀹氫箟杞暟锛岄€氳繃 query 鍙傛暟浼犻€?
  if (params.maxRounds) {
    routeParams.query = { maxRounds: params.maxRounds }
  }
  
  // 璺宠浆鍒?Step 3 椤甸潰
  router.push(routeParams)
}

// --- Data Logic ---

/**
 * 妫€鏌ュ苟鍏抽棴姝ｅ湪杩愯鐨勬ā鎷?
 * 褰撶敤鎴蜂粠 Step 3 杩斿洖鍒?Step 2 鏃讹紝榛樿鐢ㄦ埛瑕侀€€鍑烘ā鎷?
 */
const checkAndStopRunningSimulation = async () => {
  if (!currentSimulationId.value) return
  
  try {
    // 鍏堟鏌ユā鎷熺幆澧冩槸鍚﹀瓨娲?
    const envStatusRes = await getEnvStatus({ simulation_id: currentSimulationId.value })
    
    if (envStatusRes.success && envStatusRes.data?.env_alive) {
      addLog('妫€娴嬪埌妯℃嫙鐜姝ｅ湪杩愯锛屾鍦ㄥ叧闂?..')
      
      // 灏濊瘯浼橀泤鍏抽棴妯℃嫙鐜
      try {
        const closeRes = await closeSimulationEnv({ 
          simulation_id: currentSimulationId.value,
          timeout: 10  // 10绉掕秴鏃?
        })
        
        if (closeRes.success) {
          addLog('鉁?妯℃嫙鐜宸插叧闂?)
        } else {
          addLog(`鍏抽棴妯℃嫙鐜澶辫触: ${closeRes.error || '鏈煡閿欒'}`)
          // 濡傛灉浼橀泤鍏抽棴澶辫触锛屽皾璇曞己鍒跺仠姝?
          await forceStopSimulation()
        }
      } catch (closeErr) {
        addLog(`鍏抽棴妯℃嫙鐜寮傚父: ${closeErr.message}`)
        // 濡傛灉浼橀泤鍏抽棴寮傚父锛屽皾璇曞己鍒跺仠姝?
        await forceStopSimulation()
      }
    } else {
      // 鐜鏈繍琛岋紝浣嗗彲鑳借繘绋嬭繕鍦紝妫€鏌ユā鎷熺姸鎬?
      const simRes = await getSimulation(currentSimulationId.value)
      if (simRes.success && simRes.data?.status === 'running') {
        addLog('妫€娴嬪埌妯℃嫙鐘舵€佷负杩愯涓紝姝ｅ湪鍋滄...')
        await forceStopSimulation()
      }
    }
  } catch (err) {
    // 妫€鏌ョ幆澧冪姸鎬佸け璐ヤ笉褰卞搷鍚庣画娴佺▼
    console.warn('妫€鏌ユā鎷熺姸鎬佸け璐?', err)
  }
}

/**
 * 寮哄埗鍋滄妯℃嫙
 */
const forceStopSimulation = async () => {
  try {
    const stopRes = await stopSimulation({ simulation_id: currentSimulationId.value })
    if (stopRes.success) {
      addLog('鉁?妯℃嫙宸插己鍒跺仠姝?)
    } else {
      addLog(`寮哄埗鍋滄妯℃嫙澶辫触: ${stopRes.error || '鏈煡閿欒'}`)
    }
  } catch (err) {
    addLog(`寮哄埗鍋滄妯℃嫙寮傚父: ${err.message}`)
  }
}

const loadSimulationData = async () => {
  try {
    addLog(`鍔犺浇妯℃嫙鏁版嵁: ${currentSimulationId.value}`)
    
    // 鑾峰彇 simulation 淇℃伅
    const simRes = await getSimulation(currentSimulationId.value)
    if (simRes.success && simRes.data) {
      const simData = simRes.data
      
      // 鑾峰彇 project 淇℃伅
      if (simData.project_id) {
        const projRes = await getProject(simData.project_id)
        if (projRes.success && projRes.data) {
          projectData.value = projRes.data
          addLog(`椤圭洰鍔犺浇鎴愬姛: ${projRes.data.project_id}`)
          
          // 鑾峰彇 graph 鏁版嵁
          if (projRes.data.graph_id) {
            await loadGraph(projRes.data.graph_id)
          }
        }
      }
    } else {
      addLog(`鍔犺浇妯℃嫙鏁版嵁澶辫触: ${simRes.error || '鏈煡閿欒'}`)
    }
  } catch (err) {
    addLog(`鍔犺浇寮傚父: ${err.message}`)
  }
}

const loadGraph = async (graphId) => {
  graphLoading.value = true
  try {
    const res = await getGraphData(graphId)
    if (res.success) {
      graphData.value = res.data
      addLog('鍥捐氨鏁版嵁鍔犺浇鎴愬姛')
    }
  } catch (err) {
    addLog(`鍥捐氨鍔犺浇澶辫触: ${err.message}`)
  } finally {
    graphLoading.value = false
  }
}

const refreshGraph = () => {
  if (projectData.value?.graph_id) {
    loadGraph(projectData.value.graph_id)
  }
}

onMounted(async () => {
  addLog('SimulationView 鍒濆鍖?)
  
  // 妫€鏌ュ苟鍏抽棴姝ｅ湪杩愯鐨勬ā鎷燂紙鐢ㄦ埛浠?Step 3 杩斿洖鏃讹級
  await checkAndStopRunningSimulation()
  
  // 鍔犺浇妯℃嫙鏁版嵁
  loadSimulationData()
})
</script>

