 * 褰撶敤鎴蜂粠 Step 3 杩斿洖鍒?Step 2 鏃讹紝榛樿鐢ㄦ埛瑕侀€€鍑烘ā鎷?
 */
const checkAndStopRunningSimulation = async () => {
  if (!currentSimulationId.value) return
  
  try {
    // 鍏堟鏌ユā鎷熺幆澧冩槸鍚﹀瓨娲?
    const envStatusRes = await getEnvStatus({ simulation_id: currentSimulationId.value })
    
    if (envStatusRes.success && envStatusRes.data?.env_alive) {
      addLog('妫€娴嬪埌妯℃嫙鐜姝ｅ湪杩愯锛屾鍦ㄥ叧闂?..')
      
      // 灏濊瘯浼橀泤鍏抽棴妯℃嫙鐜
      try {
        const closeRes = await closeSimulationEnv({ 
          simulation_id: currentSimulationId.value,
          timeout: 10  // 10绉掕秴鏃?
        })
        
        if (closeRes.success) {
          addLog('鉁?妯℃嫙鐜宸插叧闂?)
        } else {
          addLog(`鍏抽棴妯℃嫙鐜澶辫触: ${closeRes.error || '鏈煡閿欒'}`)
          // 濡傛灉浼橀泤鍏抽棴澶辫触锛屽皾璇曞己鍒跺仠姝?
          await forceStopSimulation()
        }
      } catch (closeErr) {
        addLog(`鍏抽棴妯℃嫙鐜寮傚父: ${closeErr.message}`)
        // 濡傛灉浼橀泤鍏抽棴寮傚父锛屽皾璇曞己鍒跺仠姝?
        await forceStopSimulation()
      }
    } else {
      // 鐜鏈繍琛岋紝浣嗗彲鑳借繘绋嬭繕鍦紝妫€鏌ユā鎷熺姸鎬?
      const simRes = await getSimulation(currentSimulationId.value)
      if (simRes.success && simRes.data?.status === 'running') {
        addLog('妫€娴嬪埌妯℃嫙鐘舵€佷负杩愯涓紝姝ｅ湪鍋滄...')
        await forceStopSimulation()
      }
    }
  } catch (err) {
    // 妫€鏌ョ幆澧冪姸鎬佸け璐ヤ笉褰卞搷鍚庣画娴佺▼
    console.warn('妫€鏌ユā鎷熺姸鎬佸け璐?', err)
  }
}

/**
