 */
const forceStopSimulation = async () => {
  try {
    const stopRes = await stopSimulation({ simulation_id: currentSimulationId.value })
    if (stopRes.success) {
      addLog('鉁?妯℃嫙宸插己鍒跺仠姝?)
    } else {
      addLog(`寮哄埗鍋滄妯℃嫙澶辫触: ${stopRes.error || '鏈煡閿欒'}`)
    }
  } catch (err) {
    addLog(`寮哄埗鍋滄妯℃嫙寮傚父: ${err.message}`)
  }
}

const loadSimulationData = async () => {
  try {
    addLog(`鍔犺浇妯℃嫙鏁版嵁: ${currentSimulationId.value}`)
    
    // 鑾峰彇 simulation 淇℃伅
    const simRes = await getSimulation(currentSimulationId.value)
    if (simRes.success && simRes.data) {
      const simData = simRes.data
      
      // 鑾峰彇 project 淇℃伅
      if (simData.project_id) {
        const projRes = await getProject(simData.project_id)
        if (projRes.success && projRes.data) {
          projectData.value = projRes.data
          addLog(`椤圭洰鍔犺浇鎴愬姛: ${projRes.data.project_id}`)
          
          // 鑾峰彇 graph 鏁版嵁
          if (projRes.data.graph_id) {
            await loadGraph(projRes.data.graph_id)
          }
        }
      }
    } else {
      addLog(`鍔犺浇妯℃嫙鏁版嵁澶辫触: ${simRes.error || '鏈煡閿欒'}`)
    }
  } catch (err) {
    addLog(`鍔犺浇寮傚父: ${err.message}`)
  }
}

const loadGraph = async (graphId) => {
  graphLoading.value = true
  try {
    const res = await getGraphData(graphId)
    if (res.success) {
      graphData.value = res.data
      addLog('鍥捐氨鏁版嵁鍔犺浇鎴愬姛')
    }
  } catch (err) {
    addLog(`鍥捐氨鍔犺浇澶辫触: ${err.message}`)
  } finally {
    graphLoading.value = false
  }
}

const refreshGraph = () => {
  if (projectData.value?.graph_id) {
    loadGraph(projectData.value.graph_id)
  }
}

onMounted(async () => {
  addLog('SimulationView 鍒濆鍖?)
  
  // 妫€鏌ュ苟鍏抽棴姝ｅ湪杩愯鐨勬ā鎷燂紙鐢ㄦ埛浠?Step 3 杩斿洖鏃讹級
  await checkAndStopRunningSimulation()
  
  // 鍔犺浇妯℃嫙鏁版嵁
  loadSimulationData()
})
</script>

